import os
from rdkit import Chem
import json

smiles_list = [
    "CC1=C(C=C(C=C1)NC(=O)C2=CC=C(C=C2)CN3CCN(CC3)C)NC4=NC=CC(=N4)C5=CN=CC=C5",
    "C1=CC=C(C=C1)C(=O)NCCOCCOCCN",
    "CC1=CC=C(C=C1)S(=O)(=O)NC(=O)NN=CC2=CC=CC=C2F",
    "CC1=C(C=CC(=C1)C(=O)NC2=CC=CC=C2)C",
    "CC1=C(C(=CC=C1)Cl)NC(=O)CN2C=CN=C2"
]

patterns = [
    "c1ccccc1",
    "[#6]",
    "[CX4H3]"
]

smarts_mols = []
for pat in patterns:
    smarts_mol = Chem.MolFromSmarts(pat)
    if smarts_mol is None:
        print(f"Warning: Pattern '{pat}' is invalid")
    else:
        smarts_mols.append(smarts_mol)

os.makedirs('pred_results', exist_ok=True)
output_path = 'pred_results/pred_substructure_match.jsonl'

with open(output_path, 'w') as f:
    for smile in smiles_list:
        mol = Chem.MolFromSmiles(smile)
        if mol is None:
            score = 0
        else:
            match_found = False
            for sm in smarts_mols:
                if sm is None:
                    continue
                if mol.HasSubstructMatch(sm):
                    match_found = True
                    break
            score = 1 if match_found else 0
        result = {
            "smiles": smile,
            "match_score": score
        }
        f.write(json.dumps(result) + '\n')
